java.util.concurrent.ExecutorService pool =
    java.util.concurrent.Executors.newFixedThreadPool(4);

try {
    java.util.concurrent.Future<Integer> f = pool.submit(() -> 42);
    System.out.println(f.get());
} finally {
    pool.shutdown();
}

